.darma-loader-darma-custom-221 {
  color: var(--loader-color, #7c3aed);
  width: 90px;
  height: 14px;
  background: radial-gradient(circle closest-side,currentColor 92%,#0000) calc(100%/3) 0/calc(100%/4) 100%;
  animation: darma-loader-darma-custom-221-l2 0.5s infinite linear;
}
@keyframes darma-loader-darma-custom-221-l2 {
    100% {background-position: 0 0}
}

